from flask import Flask, request, jsonify, abort
from functools import wraps

app = Flask(__name__)

# ── Simple routes ──────────────────────────────────────────────────────────────
@app.route("/api/v1/health", methods=["GET"])
def health():
    return jsonify({"status": "ok"}), 200

@app.route("/api/v1/agent/ask", methods=["POST"])
def ask_agent():
    # Flask does not validate request body automatically — do it manually
    data = request.get_json(silent=True)
    if not data:
        abort(400, description="Request body must be JSON")

    query = data.get("query")
    if not query or not isinstance(query, str):
        abort(422, description="Field 'query' is required and must be a string")

    model = data.get("model", "claude-opus-4-5")
    max_tokens = data.get("max_tokens", 1024)

    # Synchronous Anthropic call — blocks the worker for the full duration
    import anthropic
    client = anthropic.Anthropic()
    message = client.messages.create(
        model=model,
        max_tokens=max_tokens,
        messages=[{"role": "user", "content": query}]
    )

    return jsonify({
        "query": query,
        "response": message.content[0].text,
        "model": model,
        "input_tokens": message.usage.input_tokens,
        "output_tokens": message.usage.output_tokens,
    }), 200

# ── Path parameters ────────────────────────────────────────────────────────────
@app.route("/api/v1/runs/<run_id>", methods=["GET"])
def get_run(run_id: str):
    run = runs_store.get(run_id)
    if not run:
        abort(404, description=f"Run '{run_id}' not found")
    return jsonify(run)

# ── Error handlers ─────────────────────────────────────────────────────────────
@app.errorhandler(400)
def bad_request(e):
    return jsonify({"error": "BAD_REQUEST", "message": str(e.description)}), 400

@app.errorhandler(404)
def not_found(e):
    return jsonify({"error": "NOT_FOUND", "message": str(e.description)}), 404

@app.errorhandler(422)
def unprocessable(e):
    return jsonify({"error": "VALIDATION_ERROR", "message": str(e.description)}), 422

@app.errorhandler(500)
def server_error(e):
    return jsonify({"error": "INTERNAL_ERROR", "message": "An unexpected error occurred"}), 500

from flask import Blueprint, request, jsonify, abort, g
import anthropic, uuid

# ── Blueprint definition ───────────────────────────────────────────────────────
# Each blueprint groups related routes under a shared URL prefix
agents_bp = Blueprint("agents", __name__, url_prefix="/api/v1/agents")
runs_bp   = Blueprint("runs",   __name__, url_prefix="/api/v1/runs")
tools_bp  = Blueprint("tools",  __name__, url_prefix="/api/v1/tools")

# ── Agents blueprint ───────────────────────────────────────────────────────────
agents_store = {}

@agents_bp.route("/", methods=["GET"])
def list_agents():
    return jsonify({"agents": list(agents_store.values())})

@agents_bp.route("/", methods=["POST"])
def create_agent():
    data = request.get_json(force=True)
    agent_id = str(uuid.uuid4())
    agent = {"id": agent_id, "name": data["name"], "model": data.get("model", "claude-opus-4-5")}
    agents_store[agent_id] = agent
    return jsonify(agent), 201

@agents_bp.route("/<agent_id>", methods=["GET"])
def get_agent(agent_id):
    agent = agents_store.get(agent_id)
    if not agent:
        abort(404, description=f"Agent '{agent_id}' not found")
    return jsonify(agent)

# ── Register blueprints in the application factory ──────────────────────────
def create_app(config_name="production"):
    app = Flask(__name__)

    # Load config before registering blueprints
    app.config.from_prefixed_env()   # reads FLASK_* env vars

    # Register blueprints
    app.register_blueprint(agents_bp)
    app.register_blueprint(runs_bp)
    app.register_blueprint(tools_bp)

    return app

from flask import Flask, request, session, g, jsonify
import uuid, time

app = Flask(__name__)
app.secret_key = "change-this-in-production"  # required for session

# ── Before request: runs before every route ────────────────────────────────
@app.before_request
def inject_request_id():
    # g is per-request storage — reset automatically after each request
    g.request_id = str(uuid.uuid4())
    g.start_time = time.perf_counter()

@app.before_request
def authenticate():
    # Skip auth for health check
    if request.path == "/health":
        return
    api_key = request.headers.get("X-Api-Key")
    if not api_key or api_key not in {"sk-valid-key-1", "sk-valid-key-2"}:
        from flask import abort
        abort(401, description="Invalid or missing X-Api-Key header")
    g.api_key = api_key

# ── After request: runs after every route (even on error) ──────────────────
@app.after_request
def add_tracing_headers(response):
    elapsed_ms = (time.perf_counter() - g.get("start_time", time.perf_counter())) * 1000
    response.headers["X-Request-Id"] = g.get("request_id", "unknown")
    response.headers["X-Response-Time"] = f"{elapsed_ms:.2f}ms"
    return response

# ── Teardown: always runs, used for cleanup ─────────────────────────────────
@app.teardown_appcontext
def close_db(exc):
    db = g.pop("db", None)
    if db is not None:
        db.close()   # hypothetical sync DB connection

# ── Session: signed cookie, survives across requests ────────────────────────
@app.route("/login", methods=["POST"])
def login():
    data = request.get_json()
    if data.get("password") == "correct":
        session["user_id"] = str(uuid.uuid4())
        return jsonify({"logged_in": True})
    return jsonify({"error": "Bad credentials"}), 401

@app.route("/me")
def me():
    user_id = session.get("user_id")
    if not user_id:
        return jsonify({"error": "Not authenticated"}), 401
    return jsonify({"user_id": user_id})

from flask import Flask, request, jsonify, abort
from functools import wraps
import time, uuid

app = Flask(__name__)

# ── Custom decorator: require JSON content type ────────────────────────────
def require_json(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        if not request.is_json:
            abort(415, description="Content-Type must be application/json")
        return f(*args, **kwargs)
    return decorated

# ── Custom decorator: rate limiting (simple in-memory, use Redis in prod) ──
request_counts = {}

def rate_limit(max_requests_per_minute=60):
    def decorator(f):
        @wraps(f)
        def decorated(*args, **kwargs):
            api_key = request.headers.get("X-Api-Key", "anonymous")
            now = time.time()
            window_key = f"{api_key}:{int(now // 60)}"
            count = request_counts.get(window_key, 0) + 1
            request_counts[window_key] = count
            if count > max_requests_per_minute:
                return jsonify({"error": "RATE_LIMIT_EXCEEDED",
                                "message": "Too many requests"}), 429
            return f(*args, **kwargs)
        return decorated
    return decorator

# ── Using the decorators ───────────────────────────────────────────────────
